import React from 'react';
import {View, Text, ScrollView, TouchableOpacity, StyleSheet} from 'react-native';

export default function BankConnectScreen({navigation}){
  const banks = ['Bank A','Bank B','First National','Community Bank','Credit Union'];
  return (
    <View style={styles.screen}>
      <Text style={styles.title}>Connect Your Bank</Text>
      <Text style={styles.smallText}>Secure connection powered by Plaid</Text>
      <ScrollView style={{marginTop:12}}>
        {banks.map((b,i)=>(
          <TouchableOpacity key={i} style={styles.bankItem} onPress={()=>navigation.replace('Main')}>
            <Text>{b}</Text>
          </TouchableOpacity>
        ))}
      </ScrollView>
    </View>
  );
}

const styles = StyleSheet.create({
  screen:{flex:1,padding:16},
  title:{fontSize:20,fontWeight:'700'},
  smallText:{color:'#666',marginTop:8},
  bankItem:{padding:12,backgroundColor:'#fff',borderRadius:8,marginBottom:8,borderWidth:1,borderColor:'#eee'}
});
